I cannot directly render or display a 3D image file (like a .jpg or .obj) within this chat interface. However, I can provide you with the **complete code** to render a 3D house using **Three.js**, a popular JavaScript library for 3D graphics in the browser.

You can copy the code below, save it as an `.html` file, and open it in any modern web browser to see the 3D model.

### 3D House Model (Three.js Code)

This code creates a simple house with a white body, a red roof, and a blue door, complete with lighting and shadows.

```html
<!DOCTYPE html>
<html lang="en">
<head>
    <meta charset="UTF-8">
    <meta name="viewport" content="width=device-width, initial-scale=1.0">
    <title>3D House Model</title>
    <style>
        body { margin: 0; overflow: hidden; background-color: #87CEEB; }
        canvas { display: block; }
        #info {
            position: absolute;
            top: 10px;
            width: 100%;
            text-align: center;
            color: white;
            font-family: Arial, sans-serif;
            font-weight: bold;
            text-shadow: 1px 1px 2px black;
            pointer-events: none;
        }
    </style>
</head>
<body>
    <div id="info">3D House Model (Click & Drag to Rotate)</div>

    <!-- Import Three.js from a CDN -->
    <script type="importmap">
        {
            "imports": {
                "three": "https://unpkg.com/three@0.160.0/build/three.module.js",
                "three/addons/": "https://unpkg.com/three@0.160.0/examples/jsm/"
            }
        }
    </script>

    <script type="module">
        import * as THREE from 'three';
        import { OrbitControls } from 'three/addons/controls/OrbitControls.js';

        // 1. Scene Setup
        const scene = new THREE.Scene();
        scene.background = new THREE.Color(0x87CEEB); // Sky blue
        scene.fog = new THREE.Fog(0x87CEEB, 20, 100);

        // 2. Camera Setup
        const camera = new THREE.PerspectiveCamera(60, window.innerWidth / window.innerHeight, 0.1, 1000);
        camera.position.set(5, 5, 8);
        camera.lookAt(0, 0, 0);

        // 3. Renderer Setup
        const renderer = new THREE.WebGLRenderer({ antialias: true });
        renderer.setSize(window.innerWidth, window.innerHeight);
        renderer.shadowMap.enabled = true; // Enable shadows
        document.body.appendChild(renderer.domElement);

        // 4. Controls (Orbit)
        const controls = new OrbitControls(camera, renderer.domElement);
        controls.enableDamping = true;

        // 5. Lighting
        const ambientLight = new THREE.AmbientLight(0xffffff, 0.6);
        scene.add(ambientLight);

        const dirLight = new THREE.DirectionalLight(0xffffff, 1);
        dirLight.position.set(10, 20, 10);
        dirLight.castShadow = true;
        dirLight.shadow.mapSize.width = 2048;
        dirLight.shadow.mapSize.height = 2048;
        scene.add(dirLight);

        // 6. Building the House

        // Materials
        const wallMaterial = new THREE.MeshStandardMaterial({ color: 0xffffff }); // White walls
        const roofMaterial = new THREE.MeshStandardMaterial({ color: 0xcc0000 }); // Red roof
        const doorMaterial = new THREE.MeshStandardMaterial({ color: 0x333333 }); // Dark door
        const windowMaterial = new THREE.MeshStandardMaterial({ color: 0x88ccff, transparent: true, opacity: 0.6 });

        // Group to hold the house
        const houseGroup = new THREE.Group();

        // Floor
        const floorGeo = new THREE.BoxGeometry(10, 1, 10);
        const floor = new THREE.Mesh(floorGeo, wallMaterial);
        floor.position.y = -0.5;
        floor.receiveShadow = true;
        houseGroup.add(floor);

        // Walls
        const wallHeight = 3;
        const wallDepth = 1;
        const wallWidth = 10;

        // Front Wall
        const frontWallGeo = new THREE.BoxGeometry(wallWidth, wallHeight, wallDepth);
        const frontWall = new THREE.Mesh(frontWallGeo, wallMaterial);
        frontWall.position.y = wallHeight / 2;
        frontWall.castShadow = true;
        frontWall.receiveShadow = true;
        houseGroup.add(frontWall);

        // Back Wall
        const backWallGeo = new THREE.BoxGeometry(wallWidth, wallHeight, wallDepth);
        const backWall = new THREE.Mesh(backWallGeo, wallMaterial);
        backWall.position.y = wallHeight / 2;
        backWall.position.z = -5;
        backWall.castShadow = true;
        backWall.receiveShadow = true;
        houseGroup.add(backWall);

        // Left Wall
        const leftWallGeo = new THREE.BoxGeometry(wallDepth, wallHeight, wallWidth);
        const leftWall = new THREE.Mesh(leftWallGeo, wallMaterial);
        leftWall.position.y = wallHeight / 2;
        leftWall.position.x = -5;
        leftWall.castShadow = true;
        leftWall.receiveShadow = true;
        houseGroup.add(leftWall);

        // Right Wall
        const rightWallGeo = new THREE.BoxGeometry(wallDepth, wallHeight, wallWidth);
        const rightWall = new THREE.Mesh(rightWallGeo, wallMaterial);
        rightWall.position.y = wallHeight / 2;
        rightWall.position.x = 5;
        rightWall.castShadow = true;
        rightWall.receiveShadow = true;
        houseGroup.add(rightWall);

        // Door
        const doorGeo = new THREE.BoxGeometry(1.5, 2.5, 0.2);
        const door = new THREE.Mesh(doorGeo, doorMaterial);
        door.position.set(0, 1.25, 4.9); // Slightly inside the front wall
        door.castShadow = true;
        houseGroup.add(door);

        // Windows (Simple squares)
        const windowGeo = new THREE.BoxGeometry(1.5, 1.5, 0.1);
        const win1 = new THREE.Mesh(windowGeo, windowMaterial);
        win1.position.set(-2, 2, 4.95);
        houseGroup.add(win1);

        const win2 = new THREE.Mesh(windowGeo, windowMaterial);
        win2.position.set(2, 2, 4.95);
        houseGroup.add(win2);

        // Roof (Pyramid)
        const roofGeo = new THREE.ConeGeometry(5, 2, 4);
        const roof = new THREE.Mesh(roofGeo, roofMaterial);
        roof.position.y = wallHeight + 1;
        roof.rotation.y = Math.PI / 4; // Rotate to align with walls
        roof.castShadow = true;
        roof.receiveShadow = true;
        houseGroup.add(roof);

        // Grass
        const grassGeo = new THREE.PlaneGeometry(100, 100);
        const grassMat = new THREE.MeshStandardMaterial({ color: 0x228B22 });
        const grass = new THREE.Mesh(grassGeo, grassMat);
        grass.rotation.x = -Math.PI / 2;
        grass.position.y = -0.51;
        grass.receiveShadow = true;
        scene.add(grass);

        // Add house to scene
        scene.add(houseGroup);

        // 7. Animation Loop
        function animate() {
            requestAnimationFrame(animate);
            controls.update();
            renderer.render(scene, camera);
        }

        // Handle window resize
        window.addEventListener('resize', onWindowResize, false);
        function onWindowResize() {
            camera.aspect = window.innerWidth / window.innerHeight;
            camera.updateProjectionMatrix();
            renderer.setSize(window.innerWidth, window.innerHeight);
        }

        animate();
    </script>
</body>
</html>
```

### How to use this:
1.  **Create a file:** Create a new file on your computer named `house.html`.
2.  **Paste:** Paste the code above into that file and save it.
3.  **Run:** Double-click `house.html` to open it in Chrome, Firefox, or Edge.
4.  **Interact:** You can click and drag to rotate the view, and scroll to zoom in/out.

